	(33, '{"de": "Bernhard Koschicek-Krombholz", "en": "Bernhard Koschicek-Krombholz"}', '{"de": "<p>... erwarb seinen Bachelor of Science in Informatik an der Fachhochschule Technikum Wien und seinen Bachelor of Arts in Geschichte an der Universit&auml;t Wien. Seit 2015 ist er am Institut f&uuml;r Mittelalterforschung der &Ouml;sterreichischen Akademie der Wissenschaften und seit 2017 am <a href=\"https://www.oeaw.ac.at/acdh/\" target=\"_blank\" rel=\"noopener\"><strong>ACDH</strong></a> t&auml;tig. Seine Interessensgebiete umfassen mittelalterliche Geschichte, insbesondere Osteuropa, historische Geographie, GIS, API-Entwicklung und Python.</p>", "en": "... received his BSc in Computer Science from the University of Applied Sciences Technikum Wien and his BA in History from the University of Vienna. He has been working at the Institute for Medieval Studies at the Austrian Academy of Sciences since 2015 and at ACDH since 2017. His interests are medieval history, especially Eastern Europe, historical geography, GIS, API development and Python."}', '{}', 2, 'Bernhard.Koschicek@oeaw.ac.at', '0000-0001-7608-7446', 'https://www.oeaw.ac.at/fileadmin/_processed_/8/d/csm_team_koschicek_acf8d10c9b.png', NULL, '{}', '{}', NULL, ''),
	(34, '{"de": "Hostinstitut"}', '{}', '{}', 3, NULL, NULL, NULL, NULL, '{}', '{}', 0, ''),
	(35, '{"de": "The Anthropological and Archaeological Database of Sepultures"}', '{"de": "THANADOS (The Anthropological and Archaeological Database of Sepultures) deals with the digital collection and presentation of Early Medieval cemeteries in the area of present day Austria. Within THANADOS hitherto published information on Early Medieval burials was digitized and translated to English language. The data are mapped using the CIDOC CRM and provided online. The information can be explored via a digital catalogue and within an interactive map. Cartographic visualisations as well as charts and plots are created dynamically based on real archaeological research data. It aims at providing a best practice way on how to disseminate archaeological sources and research in the 21st century against the background of digital humanities. It is closely connected to the OpenAtlas project and entirely build upon open source technology. It started in June 2019 and is funded by the go!digital NextGeneration programme of the Austrian Academy of Sciences (GDND 2018 039). Since the end of the project in 2021 THANADOS provides an online repository of all hitherto published Early Medieval cemeteries from the area of present day Austria. The project is actively carried on within further cooperations and new sites are added continuously The application is entirely open source and the code is available via GitHub under the MIT licence"}', '{}', 1, NULL, NULL, 'http://127.0.0.1:5000/static/images/logos/logo_mode_light.svg', 'https://thanados.net/', '{}', '{}', 181731, 'THANADOS'),
	(1, '{"de": "The THANADOS network", "en": "HistArchExplorer "}', '{"de": "<p><strong>THANADOS</strong> (The Anthropological and Archaeological Database of Sepultures) deals with the digital collection and presentation of Early Medieval cemeteries in the area of present day Austria. Within <strong>THANADOS</strong> hitherto published information on Early Medieval burials was digitized and translated to English language. The data are mapped using the CIDOC CRM and provided online. The information can be explored via a digital catalogue and within an interactive map. Cartographic visualisations as well as charts and plots are created dynamically based on real archaeological research data. It aims at providing a best practice way on how to disseminate archaeological sources and research in the 21st century against the background of digital humanities. It is closely connected to the OpenAtlas project and entirely build upon open source technology. It started in June 2019 and is funded by the go!digital NextGeneration programme of the Austrian Academy of Sciences (GDND 2018 039). Since the end of the project in 2021 THANADOS provides an online repository of all hitherto published Early Medieval cemeteries from the area of present day Austria. The project is actively carried on within further cooperations and new sites are added continuously The application is entirely open source and the code is available via GitHub under the MIT licence</p>", "en": "<p><strong>Lorem ipsum dolor sit amet</strong>, consetetur sadipscing elitr, sed diam nonumy eirmod tempor invidunt ut labore et dolore magna aliquyam erat, sed diam voluptua. At vero eos et accusam et justo duo dolores et ea rebum. Stet clita kasd gubergren, no sea takimata sanctus est Lorem ipsum dolor sit amet. Lorem ipsum dolor sit amet, consetetur sadipscing elitr, sed diam nonumy eirmod tempor invidunt ut labore et dolore magna aliquyam erat, sed diam voluptua. At vero eos et accusam et justo duo dolores et ea rebum. S